// ==========================================
// CONFIGURATION
// ==========================================
const TARGET_PER_STP = 2; // Bawat STP ay nagdadagdag ng 2 sa backlog

// ==========================================
// MAIN LOGIC
// ==========================================
const ledger = {}; 
const allWeeksSet = new Set();
let totalEndorsementsAllTime = 0;

// 1. PROCESS DATA
for (const item of items) {
  const json = item.json;

  // --- A. RECORD NEW DEMAND (Pumasok na Trabaho) ---
  const reqWeek = json["Week Commencing"];
  const reqDate = json["Requisition Date"];

  // Kung may Req Date, idagdag sa demand ng linggong iyon
  if (reqWeek && reqDate) {
    if (!ledger[reqWeek]) ledger[reqWeek] = { new_demand: 0, completed: 0 };
    ledger[reqWeek].new_demand += TARGET_PER_STP;
    allWeeksSet.add(reqWeek);
  }

  // --- B. RECORD ACTUALS (Natapos na Trabaho) ---
  const endorsedWeeks = json["Week Commencing (from Endorsed VAs)"];

  if (endorsedWeeks && Array.isArray(endorsedWeeks)) {
    endorsedWeeks.forEach(week => {
      if (!ledger[week]) ledger[week] = { new_demand: 0, completed: 0 };
      ledger[week].completed += 1;
      allWeeksSet.add(week);
      totalEndorsementsAllTime++;
    });
  }
}

// 2. CALCULATE AVERAGE VELOCITY (Speed)
const activeWeeksCount = Object.keys(ledger).length;
const avgVelocity = activeWeeksCount > 0 
  ? (totalEndorsementsAllTime / activeWeeksCount).toFixed(1) 
  : 0;

// 3. GENERATE ROLLING REPORT
const sortedWeeks = Array.from(allWeeksSet).sort();
let runningTotalBacklog = 0; // Eto ang "Timba" na nagca-carry over

return sortedWeeks.map(week => {
  const data = ledger[week] || { new_demand: 0, completed: 0 };

  // MATH: (Laman ng Timba Dati) + (Bagong Buhos) - (Inigib na Tubig)
  runningTotalBacklog = runningTotalBacklog + data.new_demand - data.completed;

  // Status Label
  let status = "Stable";
  if (runningTotalBacklog > 8) status = "High Backlog 🚨";
  if (data.completed > avgVelocity) status = "Good Performance 🚀";

  return {
    json: {
      week_commencing: week,

      // Column 1: ACTUALS (Ilan ang natapos niyo?)
      actual_endorsements: data.completed,

      // Column 2: SPEED (Mabilis ba kayo vs history?)
      average_weekly_rate: parseFloat(avgVelocity),

      // Column 3: NEW WORK (Ilan ang pumasok LANG ngayong week na 'to?)
      new_requirements_entered: data.new_demand,

      // Column 4: TOTAL ACTIVE BACKLOG (Ito ang gusto mo!)
      // Kasama dito ang Week 36, Week 37, etc. na hindi pa tapos.
      total_active_backlog: runningTotalBacklog, 

      status: status
    }
  };
});

// 1. GET THE LATEST WEEK DATA
// We assume the previous node output is sorted by date.
// We take the last item (Current Week).
const latestData = items[items.length - 1].json;

// 2. EXTRACT VARIABLES
const week = latestData.week_commencing;
const actual = latestData.actual_endorsements;
const newReq = latestData.new_requirements_entered;
const backlog = latestData.total_active_backlog;
const avg = latestData.average_weekly_rate;
const status = latestData.status;

// 3. DETERMINE COLORS BASED ON PERFORMANCE
// Backlog: Negative is Green (Surplus), High Positive is Red (Warning)
let backlogColor = "#e11d48"; // Red (Default: Work piling up)
let backlogText = "Pending";

if (backlog <= 0) {
    backlogColor = "#16a34a"; // Green (Surplus/Clear)
    backlogText = "Surplus (Ahead)";
} else if (backlog < 5) {
    backlogColor = "#f59e0b"; // Orange (Manageable)
}

// 4. GENERATE HTML
const html = `
<!DOCTYPE html>
<html>
<head>
<style>
  body { font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; margin: 0; padding: 0; background-color: #f3f4f6; }
  .card {
    width: 600px;
    background-color: #ffffff;
    border-radius: 12px;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
    overflow: hidden;
    border: 1px solid #e5e7eb;
  }
  .header {
    background-color: #1e293b;
    color: #ffffff;
    padding: 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
  }
  .header h1 { margin: 0; font-size: 24px; font-weight: 700; }
  .header .badge {
    background-color: #3b82f6;
    color: white;
    padding: 5px 12px;
    border-radius: 20px;
    font-size: 14px;
    font-weight: 600;
    text-transform: uppercase;
  }
  .grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1px;
    background-color: #e5e7eb; /* Creates borders between cells */
    border-bottom: 1px solid #e5e7eb;
  }
  .stat-box {
    background-color: #ffffff;
    padding: 25px 20px;
    text-align: center;
  }
  .stat-label { color: #64748b; font-size: 13px; text-transform: uppercase; letter-spacing: 0.05em; font-weight: 600; margin-bottom: 8px; }
  .stat-value { font-size: 36px; font-weight: 800; color: #0f172a; }
  .stat-sub { font-size: 14px; color: #64748b; margin-top: 4px; }

  .footer {
    padding: 15px 20px;
    background-color: #f8fafc;
    color: #64748b;
    font-size: 12px;
    text-align: right;
    border-top: 1px solid #e5e7eb;
  }

  /* Dynamic Colors */
  .text-green { color: #16a34a; }
  .text-red { color: #e11d48; }
</style>
</head>
<body>

<div class="card">
  <div class="header">
    <h1>Week ${week.split('-')[1]} Report</h1> <span class="badge">${status}</span>
  </div>

  <div class="grid">
    <div class="stat-box">
      <div class="stat-label">Actual Endorsements</div>
      <div class="stat-value">${actual}</div>
      <div class="stat-sub">Target Velocity: ${avg}/wk</div>
    </div>

    <div class="stat-box">
      <div class="stat-label">Total Active Backlog</div>
      <div class="stat-value" style="color: ${backlogColor}">
        ${backlog > 0 ? backlog : Math.abs(backlog)}
      </div>
      <div class="stat-sub" style="color: ${backlogColor}">${backlogText}</div>
    </div>
  </div>

  <div class="grid">
    <div class="stat-box" style="padding: 15px;">
      <div class="stat-label">New Requirements</div>
      <div class="stat-value" style="font-size: 24px;">+${newReq}</div>
    </div>
    <div class="stat-box" style="padding: 15px;">
      <div class="stat-label">Net Variance</div>
      <div class="stat-value" style="font-size: 24px;">${newReq - actual > 0 ? '↑' : '↓'} ${newReq - actual}</div>
    </div>
  </div>

  <div class="footer">
    Generated via n8n • Data Source: Airtable
  </div>
</div>

</body>
</html>
`;

return {
    json: {
        html: html,
        week_id: week
    }
};

